    n = int(input_data[0])
    a = list(map(int, input_data[1:n+1]))

    # For each value, find its position (1-indexed)
    pos = {}
    for i, v in enumerate(a):
        if v not in pos:
            pos[v] = i + 1  # take first occurrence

    # We need values v with pos[v] >= v (d[v] >= 0)
    # Sort by value, find longest non-decreasing subsequence of d[v]

    d_values = []
    for v in sorted(pos.keys()):
        d = pos[v] - v
        if d >= 0:
            d_values.append(d)

    # LIS non-decreasing
    tails = []
    for x in d_values:
        idx = bisect_right(tails, x)
        if idx == len(tails):
            tails.append(x)
        else:
            tails[idx] = x

    print(len(tails))

solve()

